import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../importantFile.txt"; // User input with path traversal

        String directory = "/home/user/files/";
        String fullPath = directory + userInput;

        // Validate user input to prevent directory traversal
        if (!fullPath.startsWith(directory)) {
            System.out.println("Invalid file path");
            return;
        }

        try {
            File file = new File(fullPath);
            if (!file.exists() || !file.isFile()) {
                System.out.println("File not found");
                return;
            }

            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

